import React, { useState, useEffect, useCallback } from "react";
import AppBar from "@mui/material/AppBar";
import Toolbar from "@mui/material/Toolbar";
import MenuIcon from "@mui/icons-material/Menu";
import Box from "@mui/material/Box";
import IconButton from "@mui/material/IconButton";
import Menu from "@mui/material/Menu";
import Container from "@mui/material/Container";
import Fade from "@mui/material/Fade";
import { Button } from "@mui/material";
import { Routes } from "components/Routes";
import { TopBarButtonStyle, topbarbgcolor } from "./feutures";
import icon from "Images/icon.png";

export const TopBar = () => {
  const [anchorElNav, setAnchorElNav] = useState(null);
  const [topBarOn, setTopBarOn] = useState(false);
  const [y, setY] = useState(window.scrollY);
  const handleNavigation = useCallback(
    (e) => {
      const newY = window.scrollY;
      setTopBarOn(newY < y);
      setY(newY);
    },
    [y]
  );

  useEffect(() => {
    window.addEventListener("scroll", handleNavigation);
    return () => {
      window.removeEventListener("scroll", handleNavigation);
    };
  }, [handleNavigation]);

  const handleOpenNavMenu = (event) => {
    setAnchorElNav(event.currentTarget);
  };

  const handleCloseNavMenu = () => {
    setAnchorElNav(null);
  };

  return (
    <AppBar
      position="fixed"
      elevation={1}
      sx={{
        backgroundColor: topBarOn ? "#1f1e1b" : topbarbgcolor,
        opacity: "100%",
        maxHeight: "5rem",
      }}
    >
      <Container>
        <Toolbar disableGutters>
          <Box sx={{ flexGrow: 1, display: { xs: "flex", md: "none" } }}>
            <IconButton
              size="large"
              aria-label="menu"
              aria-controls="menu-appbar"
              aria-haspopup="true"
              onClick={handleOpenNavMenu}
              color="inherit"
            >
              <MenuIcon />
            </IconButton>
            <Menu
              anchorEl={anchorElNav}
              anchorOrigin={{ vertical: "bottom", horizontal: "left" }}
              keepMounted
              transformOrigin={{ vertical: "top", horizontal: "left" }}
              open={Boolean(anchorElNav)}
              onClose={handleCloseNavMenu}
              sx={{ display: { xs: "block", md: "none" }, bgcolor: "green" }}
            >
              <div className="grid grid-flow-row gap-3">
                {Routes.map((page, i) => (
                  <Button
                    fullWidth={true}
                    sx={TopBarButtonStyle}
                    href={page.path}
                  >
                    {page.name}
                  </Button>
                ))}
              </div>
            </Menu>
          </Box>
          <Box sx={{ flexGrow: 1, display: { xs: "none", md: "flex" } }}>
            <div className="grid grid-flow-col gap-3 mx-auto">
              {Routes.map((page, i) => (
                <Button
                  fullWidth={true}
                  sx={TopBarButtonStyle}
                  href={page.path}
                >
                  {page.name}
                </Button>
              ))}
            </div>
          </Box>
        </Toolbar>
      </Container>
    </AppBar>
  );
};
